// Script Continued Below
// RJ - OU REQUEST TYPE
function onSubmit() {

	var table = 'x_153465_discovert_tasker_requests';
	var RequestSysId; 
	var modalForm;
	var title;
	var view;
	var ou_parent;

	var formAction = g_form.getActionName();

	// STRY0088787 added if statement to check the submit is a Request submit, then doin save before continuing
	if(formAction == 'request_organizational_update'){
		// If the form is dirty, ask the user if they would like to save the record
		var saveChangeConfirmation = false;
		var saveMsg = getMessage('Tasker - Modal Save Changes Message');
		if(typeof spModal != 'undefined'){
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				var fMsg = changeFieldList.join(', ');					
				saveMsg += "  " + fMsg;
				saveChangeConfirmation = true;
			}
		} else if (typeof spModal == 'undefined' && g_form.modified) {
			saveMsg += JSON.stringify(g_form.modifiedFields);
			saveChangeConfirmation = true;
		}

		// use the variable set above here to show confirmation message.
		if(saveChangeConfirmation){				
			if(confirm(saveMsg)){
				g_form.save();
			} else{
				return false;
			}
		}

		if(!g_scratchpad.OUHA_responsible.GlobalAdministrators.value && !g_scratchpad.OUHA_responsible.Administrators.value){
			// no people are available to send request, raise error
			g_form.addErrorMessage(getMessage('Tasker - There are no available Hierarchy Administrators. Please contact your Application Administrator to add Hierarchy Administrators.'));
			return false;
		}

		title = getMessage('Tasker - Title - Request Hierarchy Update');
		view = 'ou_requesttop';
		ou_parent = g_form.getUniqueValue();
		var oWidgetInput = {};
		if (typeof spModal != 'undefined' ) { 
			oWidgetInput = {table: table, sys_id: -1, view: view, u_ou_parent: ou_parent, isModal: true};
			spModal.open({
				title:  title,
				message:'',
				backdrop:'static',
				widget: 'discovertasker-formtab',
				widgetInput: oWidgetInput,
				size:'lg',
				buttons: []
			});
		} else {
			modalForm = new GlideModalForm(title, table);
			modalForm.addParm('sysparm_query','u_ou_parent='+ou_parent);
			modalForm.addParm('sysparm_view', view); //Specify a form view
			modalForm.render();
			modalForm.setSysID(-1);
			modalForm.setCompletionCallback(refreshForm);
		}

		return false;
	}

	// this is called from the Open Modal callback to refresh the form
	function refreshForm() {
		g_form.save();
	}	

}
